+fn column_widths_from_top_border(line: &str, padding: usize) -> Vec<usize> {
+    let mut widths = Vec::new();
+    let mut current = 0usize;
+    let mut first = true;
+
+    for ch in line.chars() {
+        if first {
+            first = false;
+            continue;
+        }
+
+        if ch == '\u{2510}' {
+            widths.push(current.saturating_sub(padding * 2));
+            break;
+        }
+
+        if ch == '\u{252C}' {
+            widths.push(current.saturating_sub(padding * 2));
+            current = 0;
+        } else {
+            current += 1;
+        }
+    }
+
+    widths
+}

